import { readFileSync, writeFileSync, statSync, readdirSync, mkdirSync, existsSync } from 'fs';
import { join, relative, extname, resolve } from 'path';
import { execSync } from 'child_process';
import { gzipSync } from 'zlib';

const ROOT = process.argv[2] || process.cwd();

console.log('Running composer install...');
try {
    execSync('composer install --no-dev --optimize-autoloader --no-interaction', {
        cwd: ROOT,
        stdio: 'inherit',
    });
} catch (e) {
    // Fail loud. Continuing with a half-installed vendor/ produces a bundle
    // whose autoload classmap points at files that do not exist on disk, and
    // the only sign of trouble appears at PHP-WASM runtime as cryptic
    // "include(...): Failed to open stream" errors. Better to abort here so
    // the dev sees the actual composer output above this message.
    console.error('');
    console.error('============================================================');
    console.error('composer install failed.');
    console.error('');
    console.error('Common causes:');
    console.error('  - composer is not in PATH (install from https://getcomposer.org)');
    console.error('  - network unreachable / packagist mirror down');
    console.error('  - version conflict in composer.json');
    console.error('  - missing extension required by a package (check the output above)');
    console.error('');
    console.error('Refusing to build the bundle because the autoload map would be');
    console.error('inconsistent with vendor/. Fix composer install and retry.');
    console.error('============================================================');
    process.exit(1);
}

// Pre-flight: confirm the two non-negotiable dependencies are physically
// present. composer install can technically succeed with a stale lockfile
// and still leave critical packages missing. Catching it here is much
// kinder than failing at runtime inside PHP-WASM.
const requiredVendorPaths = [
    { pkg: 'livewire/livewire', path: 'vendor/livewire/livewire/src/Livewire.php', fix: 'composer require livewire/livewire' },
    { pkg: 'nativeblade/nativeblade', path: 'vendor/nativeblade/nativeblade/src/NativeBladeServiceProvider.php', fix: 'composer require nativeblade/nativeblade' },
];
for (const dep of requiredVendorPaths) {
    if (!existsSync(join(ROOT, dep.path))) {
        console.error('');
        console.error('============================================================');
        console.error(`Required package missing from vendor/: ${dep.pkg}`);
        console.error('');
        console.error(`Expected to find: ${dep.path}`);
        console.error('');
        console.error('Fix:');
        console.error(`  ${dep.fix}`);
        console.error('============================================================');
        process.exit(1);
    }
}

const OUTPUT = join(ROOT, 'public', 'laravel-bundle.json');
const OUTPUT_GZ = OUTPUT + '.gz';
const META_OUTPUT = join(ROOT, 'public', 'bundle-meta.json');

// Detect which PHP-WASM version this project is pinned to.
// `resources/js/php-loader.js` is generated by `php artisan nativeblade:php X.Y`
// and re-exports from `@php-wasm/web-<major>-<minor>`. The portal reads this
// metadata to dynamically load the matching WASM at boot.
function detectPhpVersion() {
    const candidates = [
        join(ROOT, 'resources', 'js', 'php-loader.js'),
    ];
    for (const candidate of candidates) {
        try {
            const src = readFileSync(candidate, 'utf-8');
            const match = src.match(/@php-wasm\/web-(\d+)-(\d+)/);
            if (match) return `${match[1]}.${match[2]}`;
        } catch {}
    }
    return null;
}

const envPath = join(ROOT, '.env');
let activeLocales = new Set(['en']);
try {
    const envContent = readFileSync(envPath, 'utf-8');
    const m1 = envContent.match(/^APP_LOCALE=(\S+)/m);
    const m2 = envContent.match(/^APP_FALLBACK_LOCALE=(\S+)/m);
    if (m1) activeLocales.add(m1[1].replace(/['"]/g, ''));
    if (m2) activeLocales.add(m2[1].replace(/['"]/g, ''));
} catch {}

const localeList = [...activeLocales];
console.log(`Keeping locales: ${localeList.join(', ')}`);

const INCLUDE_DIRS = [
    'app', 'bootstrap', 'config', 'database/migrations', 'lang',
    'resources/views', 'public', 'routes', 'nativeblade-components', 'vendor',
];

const INCLUDE_FILES = ['.env', 'artisan', 'composer.json'];

const EXCLUDE_PATTERNS = [
    /\/tests?\//i,
    /\/Tests?\//i,
    /\/docs?\//i,
    /\/examples?\//i,
    /\/fixtures?\//i,
    /(?<!Resources)\/stubs?\//i,
    /\/benchmarks?\//i,
    /\/phpunit/i,
    /\/phpstan/i,
    /\/psalm/i,
    /\/pint/i,
    /\/rector/i,
    /\/infection/i,
    /\/CHANGELOG/i,
    /\/UPGRADE/i,
    /\/CONTRIBUTING/i,
    /\/AUTHORS/,
    /\/SECURITY(\.md)?$/i,
    /\/CODE_OF_CONDUCT/i,
    /\/\.github\//,
    /\/\.git\//,
    /\/\.idea\//,
    /\/node_modules\//,
    /\/vendor\/bin\//,
    /\/vendor\/nativeblade\/nativeblade\/(js|rust|resources\/js)\//,
    /\/storage\/framework\/views\//,
    /\/storage\/framework\/cache\//,
    /\/storage\/framework\/sessions\//,
    /\/storage\/logs\//,
    /platform_check\.php$/,
    /\.ide-helper\.php$/,
    /\.phpstorm\.meta\.php$/,
];

const EXCLUDE_EXTENSIONS = [
    '.md', '.txt', '.yml', '.yaml', '.xml', '.neon', '.dist',
    '.lock', '.editorconfig', '.gitignore', '.gitattributes',
    '.ico',
];

const BINARY_EXTENSIONS = ['.png', '.jpg', '.gif', '.woff', '.woff2', '.ttf'];

const MIME_TYPES = {
    '.png': 'image/png', '.jpg': 'image/jpeg', '.gif': 'image/gif',
    '.woff': 'font/woff', '.woff2': 'font/woff2', '.ttf': 'font/ttf',
};

const ALWAYS_INCLUDE = [/composer\.json$/, /autoload.*\.php$/];

function isLocaleFileToSkip(rel) {
    // Carbon: vendor/nesbot/carbon/src/Carbon/Lang/<locale>.php
    const carbonMatch = rel.match(/vendor\/nesbot\/carbon\/src\/Carbon\/Lang\/([^\/]+?)\.php$/);
    if (carbonMatch) {
        const locale = carbonMatch[1];
        if (!localeList.some(l => locale === l || locale.startsWith(l + '_') || l.startsWith(locale + '_'))) {
            return true;
        }
    }
    // Symfony translations: vendor/symfony/*/Resources/translations/messages.<locale>.xlf
    const symfonyMatch = rel.match(/vendor\/symfony\/[^\/]+\/Resources\/translations\/[^\/]+\.([^.]+)\.(xlf|yaml|yml|php)$/);
    if (symfonyMatch) {
        const locale = symfonyMatch[1];
        if (!localeList.some(l => locale === l || locale.startsWith(l + '_') || l.startsWith(locale + '_'))) {
            return true;
        }
    }
    return false;
}

function shouldInclude(filePath) {
    const rel = relative(ROOT, filePath).replace(/\\/g, '/');

    for (const pattern of ALWAYS_INCLUDE) {
        if (pattern.test(rel)) return true;
    }

    for (const pattern of EXCLUDE_PATTERNS) {
        if (pattern.test('/' + rel + '/')) return false;
    }

    if (isLocaleFileToSkip(rel)) return false;

    const ext = extname(filePath).toLowerCase();
    if (EXCLUDE_EXTENSIONS.includes(ext)) return false;
    if (BINARY_EXTENSIONS.includes(ext) && !rel.startsWith('public/')) return false;

    return true;
}

function collectFiles(dir, files = [], virtualBase = null) {
    try {
        const entries = readdirSync(dir, { withFileTypes: true });
        for (const entry of entries) {
            const realFullPath = join(dir, entry.name);
            const virtualPath = virtualBase ? join(virtualBase, entry.name) : realFullPath;
            const stat = statSync(realFullPath);
            if (stat.isDirectory()) {
                const rel = '/' + relative(ROOT, virtualPath).replace(/\\/g, '/') + '/';
                let skip = false;
                for (const pattern of EXCLUDE_PATTERNS) {
                    if (pattern.test(rel)) { skip = true; break; }
                }
                if (!skip) collectFiles(realFullPath, files, virtualPath);
            } else if (stat.isFile()) {
                if (shouldInclude(virtualPath)) {
                    files.push({ real: realFullPath, virtual: virtualPath });
                }
            }
        }
    } catch {}
    return files;
}

console.log('Bundling Laravel files...');
const bundle = {};
const sizeByPackage = {};
let totalSize = 0;
let fileCount = 0;

function track(rel, size) {
    let key = 'app';
    const m = rel.match(/^\/vendor\/([^\/]+\/[^\/]+)/);
    if (m) key = m[1];
    else {
        const topMatch = rel.match(/^\/([^\/]+)/);
        if (topMatch) key = topMatch[1];
    }
    sizeByPackage[key] = (sizeByPackage[key] || 0) + size;
}

for (const file of INCLUDE_FILES) {
    const fullPath = join(ROOT, file);
    try {
        const content = readFileSync(fullPath, 'utf-8');
        const rel = '/' + file;
        bundle[rel] = content;
        totalSize += content.length;
        track(rel, content.length);
        fileCount++;
    } catch {}
}

for (const dir of INCLUDE_DIRS) {
    const fullDir = join(ROOT, dir);
    const files = collectFiles(fullDir);
    for (const { real, virtual } of files) {
        const rel = '/' + relative(ROOT, virtual).replace(/\\/g, '/');
        try {
            const stat = statSync(real);
            if (stat.size > 2000000) continue;
            const ext = extname(real).toLowerCase();
            let content;
            if (BINARY_EXTENSIONS.includes(ext)) {
                const mime = MIME_TYPES[ext] || 'application/octet-stream';
                const b64 = readFileSync(real).toString('base64');
                content = `data:${mime};base64,${b64}`;
            } else {
                content = readFileSync(real, 'utf-8');
            }
            bundle[rel] = content;
            totalSize += content.length;
            track(rel, content.length);
            fileCount++;
        } catch {}
    }
}

const json = JSON.stringify(bundle);
writeFileSync(OUTPUT, json);

const gz = gzipSync(json, { level: 9 });
writeFileSync(OUTPUT_GZ, gz);

const phpVersion = detectPhpVersion();
const meta = {
    schema: 1,
    phpVersion: phpVersion || '8.3',
    generatedAt: new Date().toISOString(),
};
writeFileSync(META_OUTPUT, JSON.stringify(meta, null, 2));
if (!phpVersion) {
    console.warn('Could not detect PHP version from resources/js/php-loader.js; defaulting bundle-meta.json to 8.3.');
} else {
    console.log(`Bundle targets PHP ${phpVersion}.`);
}

try {
    const envContent = readFileSync(join(ROOT, '.env'), 'utf-8');
    const localeMatch = envContent.match(/APP_LOCALE=(\S+)/);
    const defaultLocale = localeMatch ? localeMatch[1] : 'en';

    writeFileSync(
        join(ROOT, 'public', 'nativeblade-locale.json'),
        JSON.stringify({ defaultLocale })
    );
    const langSrc = join(ROOT, 'lang');
    const langDst = join(ROOT, 'public', 'lang');
    if (!existsSync(langDst)) mkdirSync(langDst, { recursive: true });
    readdirSync(langSrc).filter(f => f.endsWith('.json')).forEach(f => {
        writeFileSync(join(langDst, f), readFileSync(join(langSrc, f)));
    });
} catch {}

const sizeMB = (Buffer.byteLength(json) / 1024 / 1024).toFixed(2);
const sizeGzMB = (gz.length / 1024 / 1024).toFixed(2);
console.log(`Files: ${fileCount}`);
console.log(`Bundle size:    ${sizeMB} MB  (JSON)`);
console.log(`Bundle size:    ${sizeGzMB} MB  (gzip)`);
console.log(`Output: ${OUTPUT}`);
console.log(`Output: ${OUTPUT_GZ}`);
console.log(`Output: ${META_OUTPUT}`);

const top = Object.entries(sizeByPackage).sort((a, b) => b[1] - a[1]).slice(0, 10);
console.log('\nTop 10 by size:');
for (const [pkg, size] of top) {
    const mb = (size / 1024 / 1024).toFixed(2);
    console.log(`  ${mb.padStart(6)} MB  ${pkg}`);
}
